import json,glob,collections
k=collections.Counter(); ops=collections.Counter(); types=collections.Counter()
for f in glob.glob('/workspace/YatCC/build/test/task2/*/*/answer.json'):
    try: data=json.load(open(f))
    except Exception: continue
    def walk(x):
        if isinstance(x,dict):
            if 'kind' in x: k[x['kind']]+=1
            if 'opcode' in x: ops[x['opcode']]+=1
            if 'type' in x:
                try: types[x['type']['qualType']]+=1
                except Exception: pass
            for v in x.values(): walk(v)
        elif isinstance(x,list):
            for v in x: walk(v)
    walk(data)
print('kinds'); print('\n'.join(f'{v} {n}' for n,v in k.most_common()))
print('ops'); print('\n'.join(f'{v} {n}' for n,v in ops.most_common()))
print('types top'); print('\n'.join(f'{v} {n}' for n,v in types.most_common(30)))
